previewCss:
.darma-loader-darma-custom-242 {
  color: var(--loader-color, #db2777);
  height: 27px;
  aspect-ratio: 5;
  --c: currentColor 90deg,#0000 0;
  background:
   conic-gradient(from 135deg at top   ,var(--c)),
   conic-gradient(from -45deg at bottom,var(--c)) 12.5% 100%;
  background-size: 20% 50%;
  background-repeat: repeat-x;
  clip-path: inset(0 50%);
  animation: darma-loader-darma-custom-242-l3 1s infinite linear;
}
@keyframes darma-loader-darma-custom-242-l3{
  90%,to {clip-path: inset(0)}
}

